app.use(express.json({ limit: '1kb' }));  // restrict payload size
app.use(express.urlencoded({ extended: false, limit: '1kb' }));
```

#### 2. No Helmet — Missing Security Headers (OWASP A05: Security Misconfiguration)

The app sets **zero security-related HTTP headers**. This leaves it vulnerable to:
- Clickjacking (no `X-Frame-Options`)
- MIME type sniffing attacks (no `X-Content-Type-Options`)
- Missing `Strict-Transport-Security`
- Missing `Content-Security-Policy`

**Recommendation:**
```js
const helmet = require('helmet');
app.use(helmet());
```

#### 3. No Rate Limiting (OWASP A04: Insecure Design)

Every endpoint is fully open to brute-force and denial-of-service attacks. There is no rate limiting of any kind.

**Recommendation:**
```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);
