const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);
    req.user = user;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

app.get('/users', authenticateToken, (req, res) => { /* ... */ });
```

#### 5. PII Exposure in `/users` (OWASP A01: Broken Access Control)

Even with authentication, the endpoint returns raw email addresses. Consider whether the consumer actually needs full emails, or if a masked version suffices.

**Recommendation:** Return only necessary fields, or mask sensitive data:
```js
app.get('/users', authenticateToken, (req, res) => {
  const sanitized = users.map(({ id, name }) => ({ id, name }));
  res.json(sanitized);
});
```

#### 6. No CORS Configuration (OWASP A05: Security Misconfiguration)

Without explicit CORS configuration, the default behavior depends on the client. In a browser context, you should explicitly restrict which origins can call your API.

**Recommendation:**
```js
const cors = require('cors');

app.use(cors({
  origin: 'https://your-trusted-domain.com', // NOT '*'
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

