75	function appendLog(line) {
76	  state.logLines.push(line);
77	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
78	  process.stdout.write(line + "\n");
79	
80	  // Track progress from log output
81	  // Total combinations: "[1/12]" pattern from entrypoint or ">>> N combinations queued"
82	  const totalMatch = line.match(/\[\d+\/(\d+)\]/);
83	  if (totalMatch) state.progress.totalCombinations = parseInt(totalMatch[1], 10);
84	  const queuedMatch = line.match(/>>> (\d+) combinations queued/);
85	  if (queuedMatch) state.progress.totalCombinations = parseInt(queuedMatch[1], 10);
86	
87	  // Combination completed (Test 7: "Completed in", Test 3: "DONE in")
88	  if (/Completed in \d+s/.test(line) || /\] DONE in \d+s/.test(line)) {
89	    state.progress.completedCombinations++;
90	  }
91	  // Combination failed
92	  if (/WARNING: run failed/.test(line) || /\] FAILED:/.test(line)) {
93	    state.progress.completedCombinations++;
94	    state.progress.failedCombinations++;
95	  }
96	
97	  // Individual test result (one per repetition)
98	  if (/^RESULT:/.test(line) || /^\s+RESULT:/.test(line)) {
99	    state.progress.completedRuns++;
100	  }
101	  // Extract GES from result blocks
102	  const gesMatch = line.match(/GES:\s+([\d.]+)/);
103	  if (gesMatch) state.progress.lastGES = parseFloat(gesMatch[1]);
