125	    return new Promise((resolve, reject) => {
126	      const srv = http.createServer((req, res) => this.handleRequest(req, res));
127	
128	      srv.on("error", (err: NodeJS.ErrnoException) => {
129	        if (err.code === "EADDRINUSE") {
