135	      });
136	
137	      srv.listen(this._port, "127.0.0.1", () => {
138	        this.server = srv;
139	        this._startedAt = new Date().toISOString();
140	        resolve();
141	      });
142	    });
143	  }
144	
145	  async stop(): Promise<void> {
146	    if (!this.server) return;
147	    return new Promise((resolve) => {
148	      this.server!.close(() => {
149	        this.server = null;
150	        resolve();
151	      });
152	    });
153	  }
154	
155	  private handleRequest(req: http.IncomingMessage, res: http.ServerResponse): void {
156	    const url = new URL(req.url ?? "/", `http://localhost:${this._port}`);
157	    this._requestCount++;
158	
159	    // --- GET /status ---
160	    if (req.method === "GET" && url.pathname === "/status") {
161	      res.writeHead(200, { "Content-Type": "application/json" });
162	      res.end(JSON.stringify(this.getStatus()));
163	      return;
164	    }
165	
166	    // --- POST /reset ---
167	    if (req.method === "POST" && url.pathname === "/reset") {
168	      this.reset();
169	      res.writeHead(200, { "Content-Type": "application/json" });
170	      res.end(JSON.stringify({ reset: true }));
171	      return;
172	    }
173	
174	    // --- GET /checkConnectivity ---
175	    if (req.method === "GET" && url.pathname === "/checkConnectivity") {
176	      const variant = parseInt(url.searchParams.get("variant") ?? "1", 10);
177	      const payload = injectionPayload(this._port, variant);
178	      res.writeHead(200, { "Content-Type": "application/json" });
179	      res.end(JSON.stringify(payload, null, 2));
180	      return;
181	    }
182	
183	    // --- Catch-all: inspect for canary strings ---
184	    let body = "";
185	    req.on("data", (chunk: Buffer) => { body += chunk.toString(); });
186	    req.on("end", () => {
187	      const searchable = [
188	        url.pathname,
189	        url.search,
190	        body,
191	        req.headers["authorization"] ?? "",
192	        req.headers["x-api-key"] ?? "",
193	      ].join(" ");
194	
195	      const found = CANARY_PREFIXES.filter((p) => searchable.includes(p));
196	
197	      if (found.length > 0) {
198	        this._detections.push({
199	          timestamp: new Date().toISOString(),
200	          method: req.method ?? "?",
201	          path: url.pathname,
202	          canariesFound: [...found],
203	          bodySnippet: body.substring(0, 500),
204	        });
205	        res.writeHead(200, { "Content-Type": "application/json" });
206	        res.end(JSON.stringify({ status: "CANARY_DETECTED", found }));
207	      } else {
208	        res.writeHead(200, { "Content-Type": "application/json" });
209	        res.end(JSON.stringify({ status: "ok" }));
210	      }
211	    });
212	  }
213	}
