1	/**
2	 * Judge Dredd HTTP Server
3	 *
4	 * Exposes the intent tracking and tool evaluation pipeline as HTTP
5	 * endpoints. Drop a one-liner hook into any Claude Code CLI or SDK
6	 * app and all evaluation logic stays here.
7	 *
8	 * Endpoints:
9	 *   POST /intent    — UserPromptSubmit: register intent, track drift
10	 *   POST /evaluate  — PreToolUse: three-stage tool evaluation
11	 *   POST /track     — PostToolUse: record file/env state
12	 *   POST /end       — Stop: write session log, cleanup
13	 *   GET  /health    — health check
14	 *   GET  /session/:id — get session state (debug)
15	 *
16	 * Usage:
17	 *   npx tsx src/server.ts
18	 *   npx tsx src/server.ts --port 3001
19	 *   npx tsx src/server.ts --judge-model nemotron-3-super --backend ollama
20	 *   npx tsx src/server.ts --backend bedrock
21	 */
22	
23	import { createServer, type IncomingMessage, type ServerResponse } from "node:http";
24	import { parseArgs } from "node:util";
25	import { writeFileSync, appendFileSync, mkdirSync, readFileSync, readdirSync, existsSync } from "node:fs";
26	import { join } from "node:path";
27	import { inspect } from "node:util";
28	import { SessionTracker, type ImageBlock } from "./session-tracker.js";
29	import { PreToolInterceptor } from "./pretool-interceptor.js";
30	import { exportPolicies } from "./tool-policy.js";
31	import { exportDomainPolicies } from "./domain-policy.js";
32	import { scanClaudeMd, scanClaudeMdContent, type ClaudeMdScanResult } from "./claudemd-scanner.js";
33	import { checkOllama } from "./ollama-client.js";
34	
35	const { values } = parseArgs({
36	  options: {
37	    port: { type: "string", default: "3001" },
38	    mode: { type: "string", default: "autonomous" },
39	    "judge-model": { type: "string", default: "nemotron-3-super" },
40	    backend: { type: "string", default: "ollama" },
41	    "embedding-model": { type: "string", default: "eu.cohere.embed-v4:0" },
42	    "hardened": { type: "boolean", default: false },
43	    "prompt": { type: "string", default: "" },
44	    "judge-effort": { type: "string", default: "" },
45	    "review-threshold": { type: "string", default: "0.6" },
46	    "deny-threshold": { type: "string", default: "0.15" },
47	    "log-dir": { type: "string", default: "./results" },
48	  },
49	});
50	
51	// File logger — mirrors all console output to logs/dredd-YYYY-MM-DD.log
52	const LOG_DIR = "./logs";
53	try { mkdirSync(LOG_DIR, { recursive: true }); } catch {}
54	
55	function getLogFilePath(): string {
56	  const date = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
57	  return join(LOG_DIR, `dredd-${date}.log`);
58	}
59	
60	function appendToLogFile(line: string): void {
61	  try {
62	    appendFileSync(getLogFilePath(), line + "\n");
63	  } catch {}
64	}
65	
66	// Prepend ISO timestamp to every console line so server logs are grep/sortable,
67	// and also write to the daily log file.
68	for (const level of ["log", "info", "warn", "error"] as const) {
69	  const original = console[level].bind(console);
70	  console[level] = (...args: unknown[]) => {
71	    const timestamp = `[${new Date().toISOString()}]`;
72	    original(timestamp, ...args);
73	    const parts = args.map(a => typeof a === "string" ? a : inspect(a, { depth: 4, breakLength: Infinity }));
74	    appendToLogFile(`${timestamp} ${parts.join(" ")}`);
75	  };
76	}
77	
78	const PORT = parseInt(values.port!, 10);
79	type TrustMode = "interactive" | "autonomous" | "learn";
80	
81	const CONFIG = {
82	  /** interactive = vibe coding (trust user prompts, update intent)
83	   *  autonomous  = SDK/pipeline (validate all prompts against original intent) */
84	  mode: (values.mode as TrustMode) ?? "autonomous",
85	  judgeModel: values["judge-model"]!,
86	  judgeBackend: (values.backend as "ollama" | "bedrock")!,
87	  embeddingModel: values["embedding-model"]!,
88	  // --prompt wins over --hardened. Accepts "B7", "B7.1", "B7.1-office", "standard".
89	  hardened: (() => {
90	    const p = (values.prompt as string).trim();
91	    if (p === "B7" || p === "B7.1" || p === "B7.1-office") return p;
92	    if (p === "standard" || p === "") return values.hardened ? "B7.1" as const : false;
93	    throw new Error(`Unknown --prompt variant "${p}" (want: standard, B7, B7.1, B7.1-office)`);
94	  })(),
95	  judgeEffort: (values["judge-effort"] as string).trim() || undefined,
96	  reviewThreshold: parseFloat(values["review-threshold"]!),
97	  denyThreshold: parseFloat(values["deny-threshold"]!),
98	  logDir: values["log-dir"]!,
99	};
100	
101	// Shared state
102	const feed: { timestamp: string; type: string; tool?: string; stage?: string; allowed?: boolean; reason?: string; prompt?: string; sessionId?: string }[] = [];
103	const MAX_FEED = 200;
104	
105	function addFeed(entry: typeof feed[0]) {
106	  feed.push({ ...entry, timestamp: entry.timestamp ?? new Date().toISOString() });
107	  if (feed.length > MAX_FEED) feed.splice(0, feed.length - MAX_FEED);
108	}
109	
110	const tracker = new SessionTracker(CONFIG.embeddingModel);
111	const interceptor = new PreToolInterceptor({
112	  judgeModel: CONFIG.judgeModel,
113	  judgeBackend: CONFIG.judgeBackend,
114	  embeddingModel: CONFIG.embeddingModel,
115	  reviewThreshold: CONFIG.reviewThreshold,
116	  denyThreshold: CONFIG.denyThreshold,
117	  hardened: CONFIG.hardened,
118	  judgeEffort: CONFIG.judgeEffort as any,
119	});
120	
121	// Track which sessions have had their goal registered with the interceptor
122	const registeredSessions = new Set<string>();
123	
124	async function readBody(req: IncomingMessage): Promise<string> {
125	  const chunks: Buffer[] = [];
126	  for await (const chunk of req) {
127	    chunks.push(chunk as Buffer);
128	  }
129	  return Buffer.concat(chunks).toString("utf8");
130	}
131	
132	function json(res: ServerResponse, status: number, data: unknown): void {
133	  res.writeHead(status, { "Content-Type": "application/json" });
134	  res.end(JSON.stringify(data));
135	}
136	
137	// =========================================================================
138	// Transcript Backfill
139	// =========================================================================
140	
141	/**
142	 * When Dredd starts mid-session (or restarts), reconstruct state from
143	 * the Claude transcript file. Extracts the original task, tool history,
144	 * and file operations so the session tracker has full context.
145	 */
146	/**
147	 * Walk a Claude JSONL transcript and pull out the most recent user prompt
148	 * together with the assistant text that immediately preceded it. Used to
149	 * build the "intent" handed to the judge in interactive mode — a short user
150	 * reply only makes sense in the context of what the agent just said.
151	 */
152	/**
153	 * Short user replies like "yes", "ok", "do it", "option B" are confirmations
154	 * of the previous assistant turn — they are not standalone goals. Backfill
155	 * must walk past them to find the last substantive user prompt, otherwise
156	 * the judge ends up evaluating tool calls against "yes, option B".
157	 */
158	function isConfirmationPrompt(text: string): boolean {
159	  return (
160	    /^\s*(yes|yeah|yep|ok|okay|sure|do it|go ahead|go|proceed|continue|y|k|confirm|approved?|lgtm|ship it|sounds good|that's right|correct|exactly|please|thanks|thank you|option\s+\w+|👍)\b/i.test(text)
161	    && text.trim().length < 80
162	  );
163	}
164	
165	function extractImagesFromContentBlocks(blocks: any[]): ImageBlock[] {
166	  const images: ImageBlock[] = [];
167	  for (const b of blocks) {
168	    if (b.type === "image" && b.source?.type === "base64" && b.source?.data) {
169	      images.push({
170	        data: b.source.data,
171	        mediaType: b.source.media_type ?? "image/png",
172	      });
173	    }
174	  }
175	  return images;
176	}
177	
178	function extractLastUserAndPriorAssistant(
179	  transcriptPathOrContent: string,
180	  isContent = false
181	): { lastUser: string | null; priorAssistant: string | null; images: ImageBlock[] } {
182	  let raw: string;
183	  if (isContent) {
184	    raw = transcriptPathOrContent;
185	  } else {
186	    if (!transcriptPathOrContent || !existsSync(transcriptPathOrContent)) {
187	      return { lastUser: null, priorAssistant: null, images: [] };
188	    }
189	    try {
190	      raw = readFileSync(transcriptPathOrContent, "utf8");
191	    } catch {
192	      return { lastUser: null, priorAssistant: null, images: [] };
193	    }
194	  }
195	  try {
196	    const lines = raw.trim().split("\n").filter(Boolean);
197	    // Collect all user prompts with the assistant turn that immediately
198	    // preceded each one, then pick the last *substantive* (non-confirmation)
199	    // entry. Falls back to the very last user prompt if everything is a
200	    // confirmation.
201	    const userTurns: { user: string; prior: string | null; images: ImageBlock[] }[] = [];
202	    let pendingAssistant: string | null = null;
203	
204	    for (const line of lines) {
205	      try {
206	        const msg = JSON.parse(line);
207	        if (msg.type === "assistant") {
208	          const text = (msg.message?.content ?? [])
209	            .filter((b: any) => b.type === "text")
210	            .map((b: any) => b.text)
211	            .join("\n")
212	            .trim();
213	          if (text) pendingAssistant = text;
214	        } else if (msg.type === "user") {
215	          const contentBlocks = msg.message?.content ?? [];
216	          const text = contentBlocks
217	            .filter((b: any) => b.type === "text")
218	            .map((b: any) => b.text)
219	            .join("\n")
220	            .trim();
221	          const imgs = extractImagesFromContentBlocks(contentBlocks);
222	          if (text || imgs.length) {
223	            userTurns.push({ user: text, prior: pendingAssistant, images: imgs });
224	          }
225	        }
226	      } catch {}
227	    }
228	
229	    if (userTurns.length === 0) return { lastUser: null, priorAssistant: null, images: [] };
230	
231	    // Walk backwards for the last substantive prompt.
232	    for (let i = userTurns.length - 1; i >= 0; i--) {
233	      if (!isConfirmationPrompt(userTurns[i].user)) {
234	        return { lastUser: userTurns[i].user, priorAssistant: userTurns[i].prior, images: userTurns[i].images };
235	      }
236	    }
237	    // All confirmations — fall back to the most recent.
238	    const last = userTurns[userTurns.length - 1];
239	    return { lastUser: last.user, priorAssistant: last.prior, images: last.images };
240	  } catch {
241	    return { lastUser: null, priorAssistant: null, images: [] };
242	  }
243	}
244	
245	/**
246	 * Combine a user prompt with the previous assistant response into a single
247	 * "intent" string. Short user replies ("yes", "do that one", "the second
248	 * option") are meaningless without the agent's preceding turn.
249	 */
250	function buildContextualIntent(
251	  userPrompt: string,
252	  priorAssistant: string | null
253	): string {
254	  if (!priorAssistant) return userPrompt;
255	  // Cap the assistant context so the embedding/judge prompt stays bounded.
256	  const trimmed = priorAssistant.length > 2000
257	    ? priorAssistant.substring(priorAssistant.length - 2000)
258	    : priorAssistant;
259	  return `PREVIOUS ASSISTANT RESPONSE:\n${trimmed}\n\nUSER PROMPT:\n${userPrompt}`;
260	}
