262	async function backfillFromTranscript(
263	  sessionId: string,
264	  transcriptPathOrContent: string,
265	  isContent = false
266	): Promise<void> {
267	  let raw: string;
268	  if (isContent) {
269	    raw = transcriptPathOrContent;
270	  } else {
271	    if (!transcriptPathOrContent || !existsSync(transcriptPathOrContent)) return;
272	    try {
273	      raw = readFileSync(transcriptPathOrContent, "utf8");
274	    } catch {
275	      return;
276	    }
277	  }
278	
279	  try {
280	    const lines = raw.trim().split("\n").filter(Boolean);
281	
282	    let firstUserPrompt: string | null = null;
283	    let firstUserImages: ImageBlock[] = [];
284	    let turnCount = 0;
285	    const toolCalls: { tool: string; input: Record<string, unknown> }[] = [];
286	    const filesRead: string[] = [];
287	    const filesWritten: { path: string; content: string; isEdit: boolean }[] = [];
288	
289	    for (const line of lines) {
290	      try {
291	        const msg = JSON.parse(line);
292	
293	        // Extract first user message as original intent
294	        if (msg.type === "user" && !firstUserPrompt) {
295	          const contentBlocks = msg.message?.content ?? [];
296	          const textBlocks = contentBlocks
297	            .filter((b: any) => b.type === "text")
298	            .map((b: any) => b.text);
299	          if (textBlocks.length > 0) {
300	            firstUserPrompt = textBlocks.join("\n");
301	            firstUserImages = extractImagesFromContentBlocks(contentBlocks);
302	          }
303	        }
304	
305	        // Count user messages as turns
306	        if (msg.type === "user" && msg.message?.content?.some((b: any) => b.type === "text")) {
307	          turnCount++;
308	        }
309	
310	        // Extract tool calls from assistant messages
311	        if (msg.type === "assistant") {
312	          const blocks = msg.message?.content ?? [];
313	          for (const block of blocks) {
314	            if (block.type === "tool_use") {
315	              const tool = block.name;
316	              const input = block.input ?? {};
317	              toolCalls.push({ tool, input });
318	
319	              // Track file operations
320	              if (tool === "Read") {
321	                filesRead.push(String(input.file_path ?? ""));
322	              }
323	              if (tool === "Write") {
324	                filesWritten.push({
325	                  path: String(input.file_path ?? ""),
326	                  content: String(input.content ?? ""),
327	                  isEdit: false,
328	                });
329	              }
330	              if (tool === "Edit") {
331	                filesWritten.push({
332	                  path: String(input.file_path ?? ""),
333	                  content: String(input.new_string ?? ""),
334	                  isEdit: true,
335	                });
336	              }
337	            }
338	          }
339	        }
340	      } catch {
341	        // Skip malformed lines
342	      }
343	    }
344	
345	    // Prefer the *last* user prompt (combined with the prior assistant turn)
346	    // as the goal — backfill is only used when Dredd starts mid-session, and
347	    // the most recent exchange is what the agent is currently acting on.
348	    const { lastUser, priorAssistant, images: lastImages } = extractLastUserAndPriorAssistant(raw, true);
349	    const goalPrompt = lastUser ?? firstUserPrompt;
350	    if (!goalPrompt) return;
351	    const goalImages = lastImages.length ? lastImages : firstUserImages;
352	    const contextualGoal = buildContextualIntent(goalPrompt, priorAssistant);
353	
354	    console.log(
355	      `  [BACKFILL] Session ${sessionId.substring(0, 8)}: ` +
356	      `${turnCount} turns, ${toolCalls.length} tools, ` +
357	      `${filesRead.length} reads, ${filesWritten.length} writes` +
358	      `${goalImages.length ? `, ${goalImages.length} image(s)` : ""}` +
359	      ` from transcript`
360	    );
361	
362	    // Register the most-recent intent (with prior assistant context)
363	    await tracker.registerIntent(sessionId, goalPrompt, false, goalImages);
364	    await interceptor.registerGoal(contextualGoal, goalImages);
365	    registeredSessions.add(sessionId);
366	
367	    // Replay file operations into the tracker
368	    for (const path of filesRead) {
369	      tracker.recordFileRead(sessionId, path, "(backfilled)");
370	    }
371	    for (const file of filesWritten) {
372	      tracker.recordFileWrite(sessionId, file.path, file.content, file.isEdit);
373	    }
374	
375	    // Record tool calls
376	    for (const tc of toolCalls) {
377	      tracker.recordToolCall(sessionId, tc.tool, tc.input, "allow", null);
378	    }
379	
380	    console.log(
381	      `  [BACKFILL] Latest intent: "${goalPrompt.substring(0, 60)}..." ` +
382	      `(prior assistant context: ${priorAssistant ? "yes" : "no"})`
383	    );
384	  } catch (err) {
385	    console.error(
386	      `  [BACKFILL] Failed for session ${sessionId.substring(0, 8)}: ${err instanceof Error ? err.message : String(err)}`
387	    );
388	  }
389	}
