394	async function handleIntent(req: IncomingMessage, res: ServerResponse) {
395	  const body = JSON.parse(await readBody(req));
396	  const { session_id, prompt, transcript_path, cwd } = body;
397	  // Remote-compatible fields: inline content sent by the hook
398	  const transcriptContent: string | undefined = body.transcript_content;
399	  const claudeMdContent: string | undefined = body.claudemd_content;
400	
401	  if (!session_id || !prompt) {
402	    return json(res, 400, { error: "Missing session_id or prompt" });
403	  }
404	
405	  // Store the Claude instance's working directory as the sandbox boundary.
406	  // setProjectRoot ignores subsequent calls so the first cwd wins.
407	  if (cwd) {
408	    tracker.setProjectRoot(session_id, cwd);
409	
410	    // Scan CLAUDE.md on first session contact for injection patterns
411	    if (!registeredSessions.has(session_id)) {
412	      let scan: ClaudeMdScanResult;
413	      if (claudeMdContent) {
414	        scan = scanClaudeMdContent(claudeMdContent, `${cwd}/CLAUDE.md`);
415	      } else {
416	        scan = scanClaudeMd(cwd);
417	      }
418	      if (scan.findings.length > 0) {
419	        console.warn(`  [${session_id.substring(0, 8)}] [CLAUDEMD-SCAN] ${scan.summary}`);
420	        for (const f of scan.findings) {
421	          console.warn(`    ${f.severity.toUpperCase()} ${f.pattern} (${f.file}:${f.line}): ${f.snippet}`);
422	        }
423	        tracker.recordClaudeMdScan(session_id, scan);
424	      }
425	    }
426	  }
427	
428	  // If this is a session we haven't seen and there's a transcript, backfill.
429	  // Prefer inline transcript_content (remote) over transcript_path (local).
430	  if (!registeredSessions.has(session_id)) {
431	    if (transcriptContent) {
432	      await backfillFromTranscript(session_id, transcriptContent, true);
433	    } else if (transcript_path) {
434	      await backfillFromTranscript(session_id, transcript_path);
435	    }
436	  }
437	
438	  // Allow per-request mode override (e.g., SDK sends mode in body)
439	  const mode: TrustMode = body.mode ?? CONFIG.mode;
440	
441	  // Extract images from the transcript for this user turn.
442	  // Prefer inline content over file path.
443	  const { priorAssistant, images: transcriptImages } = transcriptContent
444	    ? extractLastUserAndPriorAssistant(transcriptContent, true)
445	    : transcript_path
446	      ? extractLastUserAndPriorAssistant(transcript_path)
447	      : { priorAssistant: null, images: [] as ImageBlock[] };
448	
449	  const result = await tracker.registerIntent(session_id, prompt, mode === "interactive", transcriptImages);
450	
451	  // Build a contextual goal: the user prompt combined with the assistant
452	  // response that immediately preceded it, so short replies retain meaning.
453	  const contextualGoal = buildContextualIntent(prompt, priorAssistant);
454	
455	  if (transcriptImages.length) {
456	    console.log(
457	      `  [${session_id.substring(0, 8)}] [INTENT] ${transcriptImages.length} image(s) attached to intent`
458	    );
459	  }
460	
461	  // Register goal with interceptor on first call per session
462	  if (result.isOriginal && !registeredSessions.has(session_id)) {
463	    await interceptor.registerGoal(contextualGoal, transcriptImages);
464	    registeredSessions.add(session_id);
465	  }
466	
467	  if ((mode === "interactive" || mode === "learn") && !result.isOriginal) {
468	    // INTERACTIVE / LEARN MODE:
469	    // Every user prompt is trusted — they're steering.
470	    // But short confirmations ("yes", "ok", "do it", "go ahead") are
471	    // confirming the PREVIOUS intent, not setting a new one.
472	    // Only update the goal for substantive prompts.
473	    // Learn mode also updates intent so pipeline verdicts are evaluated
474	    // against the actual current goal, not a stale first prompt.
475	    const isConfirmation =
476	      /^\s*(yes|yeah|yep|ok|okay|sure|do it|go ahead|go|proceed|continue|y|k|confirm|approved?|lgtm|ship it|sounds good|that's right|correct|exactly|please|thanks|thank you|👍)\b/i.test(prompt)
477	      && prompt.trim().length < 80;
478	
479	    if (isConfirmation) {
480	      console.log(
481	        `  [${session_id.substring(0, 8)}] [INTENT] ${mode} mode: "${prompt.trim()}" is a confirmation — keeping previous goal`
482	      );
483	    } else {
484	      await interceptor.registerGoal(contextualGoal, transcriptImages);
485	      console.log(
486	        `  [${session_id.substring(0, 8)}] [INTENT] ${mode} mode: updated goal to "${prompt.substring(0, 60)}..." ` +
487	        `(prior assistant context: ${priorAssistant ? "yes" : "no"}, ` +
488	        `drift from original: ${result.driftFromOriginal?.toFixed(3) ?? "n/a"})`
489	      );
490	    }
491	  }
492	
493	  // Get appropriate reminder (only in autonomous mode)
494	  const classification = tracker.classifyDrift(result.driftFromOriginal);
495	  const reminder = mode === "autonomous"
496	    ? tracker.getGoalReminder(session_id, result.driftFromOriginal)
497	    : null;
498	
499	  // Build hook response
500	  const hookResponse: Record<string, unknown> = {};
501	
502	  if (reminder) {
503	    hookResponse.systemMessage = reminder;
504	  }
505	
506	  addFeed({
507	    timestamp: new Date().toISOString(),
508	    type: "intent",
509	    prompt: prompt.substring(0, 100),
510	    sessionId: session_id,
511	    reason: `Turn ${result.turnNumber}: ${classification}${result.driftFromOriginal !== null ? ` (drift: ${result.driftFromOriginal.toFixed(3)})` : ""}`,
512	  });
513	
514	  json(res, 200, {
515	    ...hookResponse,
516	    _meta: {
517	      isOriginal: result.isOriginal,
518	      turnNumber: result.turnNumber,
519	      driftFromOriginal: result.driftFromOriginal,
520	      driftFromPrevious: result.driftFromPrevious,
521	      classification,
522	    },
523	  });
524	}
