546	// POST /evaluate — PreToolUse
547	// =========================================================================
548	async function handleEvaluate(req: IncomingMessage, res: ServerResponse) {
549	  const body = JSON.parse(await readBody(req));
550	
551	  // Support benchmark format: { session, proposed_action: { tool, parameters } }
552	  const isBenchmarkFormat = body.proposed_action && body.session;
553	  const session_id: string = isBenchmarkFormat ? body.session : body.session_id;
554	  const tool_name: string = isBenchmarkFormat ? body.proposed_action.tool : body.tool_name;
555	  const tool_input: Record<string, unknown> = isBenchmarkFormat ? (body.proposed_action.parameters ?? {}) : body.tool_input;
556	  const { agent_reasoning, transcript_path } = body;
557	  const transcriptContent: string | undefined = body.transcript_content;
558	  const mode: TrustMode = body.mode ?? CONFIG.mode;
559	  const isLearn = mode === "learn";
560	
561	  if (!session_id || !tool_name) {
562	    return json(res, 400, { error: "Missing session_id or tool_name" });
563	  }
564	
565	  // If no goal registered yet, try backfill or fail-open.
566	  // Prefer inline transcript_content (remote) over transcript_path (local).
567	  if (!registeredSessions.has(session_id)) {
568	    if (transcriptContent) {
569	      await backfillFromTranscript(session_id, transcriptContent, true);
570	    } else if (transcript_path) {
571	      await backfillFromTranscript(session_id, transcript_path);
572	    }
573	
574	    // Still no goal after backfill? Allow the call — we can't evaluate
575	    // drift without a baseline. Policy deny list still applies (except in
576	    // learn mode, which only observes).
577	    if (!registeredSessions.has(session_id)) {
578	      const projectRoot = tracker.getProjectRoot(session_id);
579	      const policyOnly = (await import("./tool-policy.js")).evaluateToolPolicy(tool_name, tool_input ?? {}, projectRoot);
580	      if (policyOnly.decision === "deny" && !isLearn) {
581	        return json(res, 200, {
582	          hookSpecificOutput: {
583	            hookEventName: "PreToolUse",
584	            permissionDecision: "deny",
585	            permissionDecisionReason: `Judge Dredd (no goal): ${policyOnly.reason}`,
586	          },
587	          _meta: { allowed: false, stage: "policy-deny", reason: policyOnly.reason },
588	        });
589	      }
590	      // Allow — no goal to drift from, policy didn't deny
591	      return json(res, 200, {
592	        hookSpecificOutput: {
593	          hookEventName: "PreToolUse",
594	          permissionDecision: "allow",
595	          permissionDecisionReason: "Judge Dredd: no goal registered yet, policy allows",
596	        },
597	        _meta: { allowed: true, stage: "no-goal-allow", reason: "No goal registered, policy allows" },
598	      });
599	    }
600	  }
601	
602	  // Build file context for Bash/git commands
603	  let fileContext: string | undefined;
604	  if (tool_name === "Bash") {
605	    const command = String(tool_input?.command ?? "");
606	    const writtenFiles = tracker.getWrittenFiles(session_id);
607	
608	    const referencesWritten = writtenFiles.some((f) =>
609	      command.includes(f.path) || command.includes(f.path.split("/").pop()!)
610	    );
611	
612	    if (referencesWritten || /git\s+(add|commit|push)/.test(command)) {
613	      fileContext = tracker.getFileContextForJudge(session_id);
614	    }
615	  }
616	
617	  // Combine file context and agent reasoning for the judge
618	  let fullContext = fileContext ?? "";
619	  if (agent_reasoning) {
620	    fullContext = (fullContext ? fullContext + "\n\n" : "") +
621	      `AGENT REASONING (why it wants to use this tool):\n${agent_reasoning}`;
622	  }
623	
624	  const result = await interceptor.evaluate(
625	    tool_name,
626	    tool_input ?? {},
627	    fullContext || undefined,
628	    session_id,
629	    tracker.getProjectRoot(session_id)
630	  );
631	
632	  // In learn mode, the full pipeline runs (for logging / FPR calibration)
633	  // but we emit no `permissionDecision` in the hook response — Claude Code
634	  // falls through to the user's normal `.claude/settings.json` permission
635	  // rules exactly as if Dredd weren't installed. Verdict is still recorded
636	  // in the session log + dashboard feed for offline review.
637	
638	  // Record the decision (true verdict, regardless of learn-mode pass-through)
639	  tracker.recordToolCall(
640	    session_id,
641	    tool_name,
642	    tool_input ?? {},
643	    result.allowed ? "allow" : "deny",
644	    result.similarity
645	  );
646	
647	  addFeed({
648	    timestamp: new Date().toISOString(),
649	    type: "tool",
650	    tool: tool_name,
651	    stage: isLearn ? `${result.stage} (learn-shadow)` : result.stage,
652	    allowed: result.allowed,
653	    reason: result.reason.substring(0, 100),
654	    sessionId: session_id,
655	  });
656	
657	  if (isLearn && !result.allowed) {
658	    console.log(
659	      `  [${session_id.substring(0, 8)}] [LEARN] Would have blocked ${tool_name}: ${result.reason} — passing through to user permissions`
660	    );
661	  }
662	
663	  // Build hook response
664	  const hookResponse: Record<string, unknown> = {};
665	
666	  if (isLearn) {
667	    // Shadow mode — no decision. Claude Code uses user permissions config.
668	    // (No hookSpecificOutput at all; the empty hookResponse below carries
669	    //  only the _meta block for the dashboard.)
670	  } else if (!result.allowed) {
671	    // Use the interceptor's *current* working goal (which interactive mode
672	    // updates each turn) rather than the session's stale very-first prompt.
673	    const currentGoal = interceptor.getCurrentGoal()
674	      || tracker.getSessionContext(session_id).originalTask
675	      || "unknown";
676	    // Strip the contextual "PREVIOUS ASSISTANT RESPONSE: ..." prefix when
677	    // surfacing to the user — they only need to see the actual user prompt.
678	    const userVisibleGoal = currentGoal.includes("USER PROMPT:\n")
679	      ? currentGoal.split("USER PROMPT:\n").pop()!.trim()
680	      : currentGoal;
681	    hookResponse.hookSpecificOutput = {
682	      hookEventName: "PreToolUse",
683	      permissionDecision: "deny",
684	      permissionDecisionReason: `Judge Dredd: ${result.reason}`,
685	    };
686	    hookResponse.systemMessage =
687	      `[SECURITY] Tool call ${tool_name} was blocked. Reason: ${result.reason}. ` +
688	      `Stay focused on the current task: "${userVisibleGoal}".`;
689	  } else {
690	    // Explicitly allow — required for dontAsk/trusted mode
691	    hookResponse.hookSpecificOutput = {
692	      hookEventName: "PreToolUse",
693	      permissionDecision: "allow",
694	      permissionDecisionReason: `Judge Dredd: ${result.reason}`,
695	    };
696	  }
697	
698	  // Benchmark format: return {verdict, confidence, rationale} directly
699	  if (isBenchmarkFormat) {
700	    const verdict = result.judgeVerdict?.verdict
701	      ?? (result.allowed ? "consistent" : "hijacked");
702	    const confidence = result.judgeVerdict?.confidence ?? (result.allowed ? 0.95 : 0.90);
703	    const rationale = result.judgeVerdict?.reasoning ?? result.reason;
704	    return json(res, 200, { verdict, confidence, rationale });
705	  }
706	
707	  json(res, 200, {
708	    ...hookResponse,
709	    _meta: {
710	      allowed: result.allowed,
711	      stage: result.stage,
712	      similarity: result.similarity,
713	      reason: result.reason,
714	      evaluationMs: result.evaluationMs,
715	      judgeVerdict: result.judgeVerdict
716	        ? {
717	            verdict: result.judgeVerdict.verdict,
718	            confidence: result.judgeVerdict.confidence,
719	            reasoning: result.judgeVerdict.reasoning,
720	          }
721	        : null,
722	    },
723	  });
724	}
