1	/**
2	 * Bedrock Client
3	 *
4	 * Calls Nemotron-3-Super via Amazon Bedrock's Converse API.
5	 * Uses default AWS credentials from the environment.
6	 * Writes request to temp file to avoid shell escaping issues.
7	 */
8	
9	import { execSync } from "node:child_process";
10	import { writeFileSync, readFileSync, unlinkSync } from "node:fs";
11	import { join } from "node:path";
12	import { tmpdir } from "node:os";
13	
14	const REGION = process.env.BEDROCK_REGION ?? process.env.AWS_REGION ?? "eu-central-1";
15	const MODEL_ID = process.env.BEDROCK_JUDGE_MODEL ?? "nvidia.nemotron-super-3-120b";
16	
17	type EffortLevel = "low" | "medium" | "high" | "xhigh" | "max" | "none";
18	
19	export interface BedrockImageBlock {
20	  /** Base64-encoded image data */
21	  data: string;
22	  /** MIME type, e.g. "image/png" */
23	  mediaType: string;
24	}
25	
26	export async function bedrockChat(
27	  systemPrompt: string,
28	  userMessage: string,
29	  modelId = MODEL_ID,
30	  effort?: EffortLevel,
31	  images?: BedrockImageBlock[]
32	): Promise<{
33	  content: string;
34	  thinking: string;
35	  durationMs: number;
36	  inputTokens: number;
37	  outputTokens: number;
38	  totalTokens: number;
39	  cacheReadInputTokens?: number;
40	  cacheWriteInputTokens?: number;
41	  hasThinkingBlock: boolean;
42	  estimatedThinkingTokens: number;
43	}> {
44	  const start = Date.now();
45	  if (effort === "none") effort = undefined;
46	
47	  // Write request components to temp files to avoid shell escaping
48	  const tmpMessages = join(tmpdir(), `bedrock-msg-${Date.now()}.json`);
49	  const tmpSystem = join(tmpdir(), `bedrock-sys-${Date.now()}.json`);
50	  const tmpConfig = join(tmpdir(), `bedrock-cfg-${Date.now()}.json`);
51	  let tmpThinking: string | null = null;
52	
53	  try {
54	    const userContent: Record<string, unknown>[] = [{ text: userMessage }];
55	    if (images?.length) {
56	      for (const img of images) {
57	        const format = img.mediaType.replace("image/", "");
58	        userContent.push({
59	          image: { format, source: { bytes: img.data } },
60	        });
61	      }
62	    }
63	    writeFileSync(tmpMessages, JSON.stringify([
64	      {
65	        role: "user",
66	        content: userContent,
67	      },
68	    ]));
69	
70	    writeFileSync(tmpSystem, JSON.stringify([
71	      { text: systemPrompt },
72	    ]));
73	
74	    const budgetMap: Record<string, number> = { low: 1024, medium: 5000, high: 16000, max: 60000 };
75	    const budgetTokens = budgetMap[effort!] ?? 5000;
76	    const isOpus47 = modelId.includes("opus-4-7");
77	    const inferenceConfig: Record<string, unknown> = {
78	      maxTokens: effort ? (isOpus47 ? 16384 : Math.min(budgetTokens + 4096, 64000)) : 512,
79	    };
80	    if (!isOpus47) inferenceConfig.temperature = effort ? 1 : 0.1;
81	    writeFileSync(tmpConfig, JSON.stringify(inferenceConfig));
82	
83	    const cmdParts = [
84	      "aws", "bedrock-runtime", "converse",
85	      "--region", REGION,
86	      "--model-id", modelId,
87	      "--messages", `file://${tmpMessages}`,
88	      "--system", `file://${tmpSystem}`,
89	      "--inference-config", `file://${tmpConfig}`,
90	      "--output", "json",
91	    ];
92	
93	    if (effort) {
94	      tmpThinking = join(tmpdir(), `bedrock-think-${Date.now()}.json`);
95	      const thinkingFields = isOpus47
96	        ? { thinking: { type: "adaptive" }, output_config: { effort } }
97	        : { thinking: { type: "enabled", budget_tokens: budgetTokens } };
98	      writeFileSync(tmpThinking, JSON.stringify(thinkingFields));
99	      cmdParts.push("--additional-model-request-fields", `file://${tmpThinking}`);
100	    }
101	
102	    const cmd = cmdParts.join(" ");
103	
104	    const result = execSync(cmd, {
105	      encoding: "utf8",
106	      maxBuffer: 1024 * 1024,
107	      timeout: 120000,
108	    });
109	
110	    const parsed = JSON.parse(result);
111	    const blocks = parsed.output.message.content as Record<string, unknown>[];
112	    const content = blocks
113	      .filter((c) => c.text !== undefined)
114	      .map((c) => c.text as string)
115	      .join("");
116	    const thinking = blocks
117	      .filter((c) => c.reasoningContent !== undefined)
118	      .map((c) => {
119	        const rc = c.reasoningContent as Record<string, unknown>;
120	        const rt = rc.reasoningText as Record<string, unknown> | undefined;
121	        return ((rt?.text ?? rc.text ?? "") as string);
122	      })
123	      .join("");
124	
125	    const usage = parsed.usage ?? {};
126	    const inputTokens = usage.inputTokens ?? 0;
127	    const outputTokens = usage.outputTokens ?? 0;
128	    const hasThinkingBlock = blocks.some((c) => c.reasoningContent !== undefined);
129	    return {
130	      content,
131	      thinking,
132	      durationMs: Date.now() - start,
133	      inputTokens,
134	      outputTokens,
135	      totalTokens: usage.totalTokens ?? (inputTokens + outputTokens),
136	      cacheReadInputTokens: usage.cacheReadInputTokens,
137	      cacheWriteInputTokens: usage.cacheWriteInputTokens,
138	      hasThinkingBlock,
139	      estimatedThinkingTokens: thinking ? Math.ceil(thinking.length / 4) : 0,
140	    };
141	  } finally {
142	    try { unlinkSync(tmpMessages); } catch {}
143	    try { unlinkSync(tmpSystem); } catch {}
144	    try { unlinkSync(tmpConfig); } catch {}
145	    if (tmpThinking) try { unlinkSync(tmpThinking); } catch {}
146	  }
147	}
148	
149	// ============================================================================
150	// Embedding API
151	// ============================================================================
152	
153	/**
154	 * Embed a batch of texts using a Bedrock embedding model.
155	 * Dispatches to the correct request/response format per model family.
156	 */
157	export async function bedrockEmbed(
158	  texts: string[],
159	  modelId: string,
160	  region = REGION
161	): Promise<number[][]> {
162	  // Strip cross-region inference profile prefixes (eu., us., global.) before dispatch
163	  const bare = modelId.replace(/^(?:eu|us|global)\./, "");
164	
165	  if (bare.startsWith("cohere.embed")) {
166	    return cohereEmbed(texts, modelId, region);
167	  }
168	  if (bare.startsWith("amazon.titan-embed")) {
169	    return Promise.all(texts.map((t) => titanEmbed(t, modelId, region)));
170	  }
171	  if (bare.startsWith("twelvelabs.")) {
172	    return Promise.all(texts.map((t) => marengoEmbed(t, modelId, region)));
173	  }
174	  throw new Error(`Unknown Bedrock embedding model family: ${modelId}`);
175	}
176	
177	function invokeModel(modelId: string, body: object, region: string): object {
178	  const tmpIn  = join(tmpdir(), `bedrock-embed-in-${Date.now()}-${Math.random().toString(36).slice(2)}.json`);
179	  const tmpOut = join(tmpdir(), `bedrock-embed-out-${Date.now()}-${Math.random().toString(36).slice(2)}.json`);
180	  try {
181	    writeFileSync(tmpIn, JSON.stringify(body));
182	    const cmd = [
183	      "aws", "bedrock-runtime", "invoke-model",
184	      "--region", region,
185	      "--model-id", modelId,
186	      "--body", `file://${tmpIn}`,
187	      "--cli-binary-format", "raw-in-base64-out",
188	      tmpOut,
189	    ].join(" ");
190	    execSync(cmd, { encoding: "utf8", timeout: 30000, maxBuffer: 4 * 1024 * 1024 });
191	    return JSON.parse(readFileSync(tmpOut, "utf8"));
192	  } finally {
193	    try { unlinkSync(tmpIn); } catch {}
194	    try { unlinkSync(tmpOut); } catch {}
195	  }
196	}
197	
198	function cohereEmbed(texts: string[], modelId: string, region: string): number[][] {
199	  const resp = invokeModel(modelId, { texts, input_type: "search_query" }, region) as Record<string, unknown>;
200	  // v3: { embeddings: number[][] }
201	  // v4: { embeddings: { float: number[][] } }
202	  const emb = resp.embeddings as number[][] | { float: number[][] };
203	  return Array.isArray(emb) ? emb : emb.float;
204	}
205	
206	function titanEmbed(text: string, modelId: string, region: string): number[] {
207	  const resp = invokeModel(modelId, { inputText: text }, region) as { embedding: number[] };
208	  return resp.embedding;
209	}
210	
211	function marengoEmbed(text: string, modelId: string, region: string): number[] {
212	  // Marengo 3.0: { inputType: "text", text: { text: "..." } }
213	  // Marengo 2.7: { inputText: "..." }  (Titan-compatible schema)
214	  const bare = modelId.replace(/^(?:eu|us|global)\./, "");
215	  const body = bare.includes("marengo-embed-2-7")
216	    ? { inputType: "text", inputText: text }
217	    : { inputType: "text", text: { inputText: text } };
218	
219	  const resp = invokeModel(modelId, body, region) as Record<string, unknown>;
220	  if (Array.isArray(resp.embedding)) return resp.embedding as number[];
221	  const data = resp.data as { embedding: number[] }[] | undefined;
222	  if (data?.[0]?.embedding) return data[0].embedding;
223	  throw new Error(`Unexpected Marengo response shape: ${JSON.stringify(resp).substring(0, 200)}`);
224	}
225	
226	export async function checkBedrock(modelId = MODEL_ID): Promise<boolean> {
227	  // Test with a real converse call — avoids needing metadata API permissions
228	  // (bedrock:ListInferenceProfiles, bedrock:GetFoundationModel).
229	  try {
230	    execSync(
231	      `aws bedrock-runtime converse --region ${REGION} --model-id "${modelId}" --messages '[{"role":"user","content":[{"text":"ok"}]}]' --inference-config '{"maxTokens":1}' --output text --query "output.message.content[0].text" 2>/dev/null`,
232	      { encoding: "utf8", timeout: 15000 }
233	    );
234	    return true;
235	  } catch {
236	    return false;
237	  }
238	}
