81	// =========================================================================
82	// Agent turn execution (shared by T4/T5/T6)
83	// =========================================================================
84	
85	interface TurnResult {
86	  turn: TurnLog;
87	  assistantText: string;
88	  sessionId: string | undefined;
89	}
90	
91	async function runAgentTurn(
92	  userMessage: string,
93	  workDir: string,
94	  model: string,
95	  effort: string | undefined,
96	  sessionId: string | undefined,
97	  turnNum: number,
98	): Promise<TurnResult> {
99	  const bedrockModel = resolveBedrockModel(model);
100	  const bedrockRegion = process.env.AWS_REGION ?? "eu-west-2";
101	  const turnStart = Date.now();
102	  const turnToolCalls: ToolCallLog[] = [];
103	  let assistantText = "";
104	  let currentSessionId = sessionId;
105	
106	  try {
107	    const queryOptions: Record<string, unknown> = {
108	      allowedTools: ["Read", "Write", "Edit", "Bash", "Glob", "Grep"],
109	      permissionMode: "bypassPermissions",
110	      maxTurns: 5,
111	      cwd: workDir,
112	      model: bedrockModel,
113	      stderr: (data: string) => process.stderr.write(data),
114	      env: {
115	        ...process.env,
116	        CLAUDE_CODE_USE_BEDROCK: "1",
117	        AWS_REGION: bedrockRegion,
118	      },
119	    };
120	
121	    if (effort) {
122	      queryOptions.effort = effort;
123	    }
124	    if (currentSessionId) {
125	      queryOptions.resumeSessionId = currentSessionId;
126	    }
127	
128	    for await (const message of query({
129	      prompt: userMessage,
130	      options: queryOptions as any,
131	    })) {
132	      if (message.type === "system" && (message as any).subtype === "init") {
133	        currentSessionId = (message as any).session_id ?? currentSessionId;
134	      }
135	
136	      if (message.type === "assistant") {
137	        const content = (message as any).message?.content ?? [];
138	        for (const block of content) {
139	          if (block.type === "text") {
140	            assistantText += block.text;
141	          }
142	          if (block.type === "tool_use") {
143	            turnToolCalls.push({
144	              tool: block.name,
145	              input: block.input ?? {},
146	              output: "",
147	              canaryInInput: detectCanaries(JSON.stringify(block.input ?? {})).length > 0,
148	              canaryInOutput: false,
149	              durationMs: null,
150	              _startMs: Date.now(),
151	            } as ToolCallLog & { _startMs: number });
152	          }
153	        }
154	      }
155	
156	      if (message.type === "user") {
157	        const content = (message as any).message?.content ?? [];
158	        for (const block of content) {
159	          if (block.type === "tool_result") {
160	            const resultText =
161	              typeof block.content === "string"
162	                ? block.content
163	                : JSON.stringify(block.content ?? "").substring(0, 2000);
164	
165	            const pending = turnToolCalls.find((tc) => !tc.output);
166	            if (pending) {
167	              pending.output = resultText;
168	              pending.canaryInOutput = detectCanaries(resultText).length > 0;
169	              const p = pending as ToolCallLog & { _startMs?: number };
170	              if (p._startMs) {
171	                pending.durationMs = Date.now() - p._startMs;
172	                delete p._startMs;
173	              }
174	            }
175	          }
176	        }
177	      }
178	
179	      if (message.type === "result") {
180	        currentSessionId = (message as any).session_id ?? currentSessionId;
181	        if ((message as any).result) {
182	          assistantText += (message as any).result;
183	        }
184	      }
185	    }
186	  } catch (err) {
187	    const errMsg = err instanceof Error ? err.message : String(err);
188	    console.error(`  [QUERY ERROR] ${errMsg}`);
189	    assistantText += `[ERROR: ${errMsg}]`;
190	  }
191	
192	  for (const tc of turnToolCalls) {
193	    delete (tc as any)._startMs;
194	  }
195	
196	  const allText = [
197	    assistantText,
198	    ...turnToolCalls.map((tc) => JSON.stringify(tc.input) + tc.output),
199	  ].join(" ");
200	  const turnCanaries = [...new Set(detectCanaries(allText))];
201	
202	  const turn: TurnLog = {
203	    turnNumber: turnNum,
204	    timestamp: new Date().toISOString(),
205	    userMessage,
206	    toolCalls: turnToolCalls,
207	    assistantResponse: assistantText,
208	    canaryDetected: turnCanaries.length > 0,
209	    canariesFound: turnCanaries,
210	    durationMs: Date.now() - turnStart,
211	  };
212	
213	  return { turn, assistantText, sessionId: currentSessionId };
214	}
